CREATE TABLE "receiptNumbersDB" (`id` integer PRIMARY KEY AUTOINCREMENT NOT NULL, `user_created` char(36) NULL, `date_created` datetime NULL, `user_updated` char(36) NULL, `date_updated` datetime NULL, `receiptNumber` varchar(255) NULL DEFAULT '69129999', `receiptType` varchar(255) NULL DEFAULT null, `yearMonth` varchar(255) NULL DEFAULT '9612', `serialNumber` integer NULL DEFAULT null, `recordId` integer NULL DEFAULT null, `createdAt` varchar(255) NULL, `updatedAt` varchar(255) NULL, `state` varchar(255) NULL DEFAULT 'active', `voidReason` varchar(255) NULL DEFAULT '作廢原因', CONSTRAINT `receiptnumbersdb_user_created_foreign` FOREIGN KEY (`user_created`) REFERENCES `directus_users` (`id`), CONSTRAINT `receiptnumbersdb_user_updated_foreign` FOREIGN KEY (`user_updated`) REFERENCES `directus_users` (`id`))